import { useReducer } from 'react';

const initialState = { items: [], total: 0 };

function cartReducer(state, action) {
  switch (action.type) {
    case 'ADD_ITEM': {
      const existing = state.items.find(i => i.id === action.payload.id);
      if (existing) {
        return {
          ...state,
          items: state.items.map(i =>
            i.id === action.payload.id ? { ...i, qty: i.qty + 1 } : i
          ),
          total: state.total + action.payload.price
        };
      }
      return {
        items: [...state.items, { ...action.payload, qty: 1 }],
        total: state.total + action.payload.price
      };
    }
    case 'REMOVE_ITEM':
      return {
        items: state.items.filter(i => i.id !== action.payload),
        total: state.total - state.items.find(i => i.id === action.payload).price
      };
    case 'CLEAR_CART':
      return initialState;
    default:
      return state;
  }
}

function Cart() {
  const [state, dispatch] = useReducer(cartReducer, initialState);

  return (
    <div>
      <button onClick={() => dispatch({ type: 'ADD_ITEM', payload: { id: 1, name: 'Apple', price: 1.5 } })}>
        Add Apple
      </button>
      <p>Total: ${state.total.toFixed(2)}</p>
      <ul>{state.items.map(i => <li key={i.id}>{i.name} x{i.qty}</li>)}</ul>
      <button onClick={() => dispatch({ type: 'CLEAR_CART' })}>Clear</button>
    </div>
  );
}

