// Memoize the component itself
const Item = memo(({ item, onClick }) => (
  <div onClick={() => onClick(item.id)}>{item.name}: {item.value}</div>
));

function ExpensiveList({ items, onItemClick }) {
  // useMemo: only recalculate when items changes
  const sorted = useMemo(() => {
    console.log('Sorting...');
    return [...items].sort((a, b) => a.value - b.value);
  }, [items]);

  // useCallback: stable function reference prevents Item re-renders
  const handleClick = useCallback((id) => {
    onItemClick(id);
  }, [onItemClick]);

  return sorted.map(item => (
    <Item key={item.id} item={item} onClick={handleClick} />
  ));
}

