import { useState } from 'react';

function LoginForm() {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [errors, setErrors] = useState({});
  const [submitted, setSubmitted] = useState(false);

  const validate = () => {
    const errs = {};
    if (!formData.email.includes('@')) errs.email = 'Valid email required';
    if (formData.password.length < 8) errs.password = 'Min 8 characters';
    return errs;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (errors[name]) setErrors(prev => ({ ...prev, [name]: '' }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length > 0) {
      setErrors(errs);
      return;
    }
    setSubmitted(true);
    console.log('Submitting:', formData);
  };

  if (submitted) return <p>Welcome!</p>;

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <input name="email" type="email" value={formData.email}
          onChange={handleChange} placeholder="Email" />
        {errors.email && <span style={{color:'red'}}>{errors.email}</span>}
      </div>
      <div>
        <input name="password" type="password" value={formData.password}
          onChange={handleChange} placeholder="Password" />
        {errors.password && <span style={{color:'red'}}>{errors.password}</span>}
      </div>
      <button type="submit">Login</button>
    </form>
  );
}
